-- Create Standard Access Request Workflow
INSERT INTO approvalWorkflows (name, description, processType, isDefault, isActive, priority, createdBy)
VALUES ('Standard Access Request', 'Default workflow for all access requests with L1 (Initial Review) and L2 (Security Approval) stages', 'admin_visit', true, true, 100, 1);

SET @workflow_id = LAST_INSERT_ID();

-- Create L1 Stage (Initial Review)
INSERT INTO approvalStages (workflowId, stageOrder, stageName, stageType, approvalMode, requiredApprovals, canReject, canRequestInfo, slaHours, autoApproveOnSla, autoRejectOnSla, isConditional)
VALUES (@workflow_id, 1, 'L1 - Initial Review', 'role', 'any', 1, true, true, 24, false, false, false);

SET @l1_stage_id = LAST_INSERT_ID();

-- Create L2 Stage (Security Approval)
INSERT INTO approvalStages (workflowId, stageOrder, stageName, stageType, approvalMode, requiredApprovals, canReject, canRequestInfo, slaHours, autoApproveOnSla, autoRejectOnSla, isConditional)
VALUES (@workflow_id, 2, 'L2 - Security Approval', 'role', 'any', 1, true, true, 48, false, false, false);

SET @l2_stage_id = LAST_INSERT_ID();

-- Get or create L1 Approver role
INSERT INTO approvalRoles (roleName, roleCode, description, category, isActive)
VALUES ('L1 Approver', 'L1_APPROVER', 'Initial review and validation of access requests', 'operations', true)
ON DUPLICATE KEY UPDATE id=LAST_INSERT_ID(id);

SET @l1_role_id = LAST_INSERT_ID();

-- Get or create L2 Approver role  
INSERT INTO approvalRoles (roleName, roleCode, description, category, isActive)
VALUES ('L2 Security Approver', 'L2_APPROVER', 'Final security verification and access card assignment', 'security', true)
ON DUPLICATE KEY UPDATE id=LAST_INSERT_ID(id);

SET @l2_role_id = LAST_INSERT_ID();

-- Link L1 stage to L1 Approver role
INSERT INTO stageApprovers (stageId, approverType, approverValue, priority, isRequired)
VALUES (@l1_stage_id, 'role', @l1_role_id, 1, true);

-- Link L2 stage to L2 Approver role
INSERT INTO stageApprovers (stageId, approverType, approverValue, priority, isRequired)
VALUES (@l2_stage_id, 'role', @l2_role_id, 1, true);

-- Assign admin user to both approval roles
INSERT INTO userApprovalRoles (userId, approvalRoleId, isPrimary, isActive)
SELECT 1, @l1_role_id, true, true
WHERE NOT EXISTS (SELECT 1 FROM userApprovalRoles WHERE userId = 1 AND approvalRoleId = @l1_role_id);

INSERT INTO userApprovalRoles (userId, approvalRoleId, isPrimary, isActive)
SELECT 1, @l2_role_id, true, true
WHERE NOT EXISTS (SELECT 1 FROM userApprovalRoles WHERE userId = 1 AND approvalRoleId = @l2_role_id);

